            ['id' => 45, 'label' => 'خاتمة',       'value' => 'الرمال لا تحتفظ بالأثر طويلاً لكنها تحتفظ بالبذور، وكل حكاية نزرعها في الأجيال هي بذرة ستنبت حين تأتي الأمطار.',                                                                                                            'book_id' => 9,  'created_at' => '2023-09-17 11:30:00', 'updated_at' => '2023-09-17 11:30:00'],
